-- เพิ่มคำถามสัมภาษณ์ที่หลากหลายและทันสถานการณ์ปัจจุบัน (AI, ความยั่งยืน/ESG,
-- สุขภาพจิต, สังคมสูงวัย, PDPA/ความเป็นส่วนตัว, ข่าวปลอม, เศรษฐกิจดิจิทัล ฯลฯ)
-- เพิ่มหมวดละ ~5 ข้อ ครบทุกคณะ — apply กับโปรเจกต์ guidance-library แล้วเมื่อ 2026-07-18
-- รวมคำถามในระบบจาก 76 → 122 ข้อ

-- ── ทั่วไป ──
with c as (select id from iv_categories where name='คำถามทั่วไป')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('คุณใช้ AI เช่น ChatGPT ช่วยเรียนอย่างไร และคิดว่าใช้แบบไหนถึงเรียกว่าเหมาะสม','แสดงว่าใช้เป็นเครื่องมือช่วยคิด/ตรวจงาน ไม่ใช่ลอกทั้งหมด เข้าใจเส้นแบ่งความซื่อสัตย์ทางวิชาการ ยกตัวอย่างการใช้จริงของตัวเอง','medium',150),
('ถ้าให้เล่าเรื่องที่ทำให้คุณ "เปลี่ยนความคิด" ในช่วง 1 ปีที่ผ่านมา','เลือกเรื่องจริง เล่าว่าเดิมคิดอย่างไร เจออะไรจึงเปลี่ยน และเปลี่ยนเป็นอย่างไร แสดงการเปิดใจและเติบโต','medium',150),
('คุณคิดว่าคนรุ่นคุณ (Gen Z) มีจุดแข็งและถูกเข้าใจผิดเรื่องอะไรบ้าง','ตอบอย่างสมดุล ไม่เข้าข้างตัวเองเกินไป ยอมรับทั้งจุดแข็ง (ปรับตัวเร็ว กล้าตั้งคำถาม) และภาพที่ถูกมองผิด พร้อมเหตุผล','medium',150),
('ถ้ามีเวลาว่าง 1 เดือนและงบจำกัด คุณจะทำโปรเจกต์อะไรที่เป็นประโยชน์','แสดงความคิดริเริ่มและการวางแผนที่ทำได้จริง เชื่อมกับความสนใจ/สาขา เน้นคุณค่าที่เกิดขึ้น','medium',150),
('คุณดูแลสุขภาพใจตัวเองอย่างไรเวลาเครียดหรือกดดัน','ตอบตามจริงด้วยวิธีที่ใช้ได้ผล แสดงว่ารู้จักขอความช่วยเหลือเมื่อจำเป็น ไม่เก็บกดคนเดียว','medium',120),
('ข่าวหรือประเด็นสังคมล่าสุดที่คุณให้ความสนใจคืออะไร เพราะอะไร','เตรียมเรื่องจริงที่ทันสมัย เล่าข้อเท็จจริงก่อนแล้วให้ความเห็นอย่างมีเหตุผล เปิดรับมุมมองต่าง','medium',150)
) as t(q,g,d,s);

-- ── แพทย์ พยาบาล สาธารณสุข ──
with c as (select id from iv_categories where name='แพทย์ · พยาบาล · สาธารณสุข')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('คิดอย่างไรกับการนำ AI มาช่วยวินิจฉัยโรค จะแทนที่แพทย์ได้ไหม','มุมมองสมดุล: AI ช่วยเพิ่มความแม่นยำและความเร็ว แต่การตัดสินใจ ความรับผิดชอบ และการดูแลด้านจิตใจยังต้องการแพทย์ เน้นใช้เป็นผู้ช่วย','hard',180),
('สังคมผู้สูงอายุของไทยส่งผลต่อระบบสาธารณสุขอย่างไร และควรเตรียมรับมืออย่างไร','เข้าใจภาพ: โรคเรื้อรังเพิ่ม บุคลากรและงบไม่พอ ต้องเน้นการป้องกัน การดูแลที่บ้าน และระบบดูแลระยะยาว','hard',180),
('คิดอย่างไรกับปัญหาสุขภาพจิตในวัยรุ่นที่เพิ่มขึ้น บุคลากรสาธารณสุขช่วยได้อย่างไร','แสดงความเข้าใจว่าเป็นปัญหาจริงจัง ลดการตีตรา ส่งเสริมการเข้าถึงบริการ และบทบาทเชิงป้องกันในชุมชน/โรงเรียน','hard',180),
('ถ้ามีข่าวปลอมด้านสุขภาพระบาดในโซเชียล คุณในฐานะบุคลากรจะทำอย่างไร','เน้นการให้ข้อมูลที่ถูกต้องเข้าใจง่าย อ้างอิงหลักฐาน สื่อสารด้วยความเข้าใจไม่ดูถูกคนเชื่อ','medium',150),
('บทเรียนจากโควิด-19 เรื่องไหนที่คุณคิดว่าสำคัญที่สุดต่อระบบสาธารณสุขไทย','เลือกประเด็นที่วิเคราะห์ได้ เช่น ความสำคัญของ อสม./ปฐมภูมิ การสื่อสารความเสี่ยง หรือความพร้อมรับภาวะฉุกเฉิน','hard',180)
) as t(q,g,d,s);

-- ── วิศวกรรม วิทยาศาสตร์ เทคโนโลยี ──
with c as (select id from iv_categories where name='วิศวกรรม · วิทยาศาสตร์ · เทคโนโลยี')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('Generative AI เปลี่ยนวิธีทำงานของวิศวกร/นักวิทยาศาสตร์อย่างไร คุณจะปรับตัวอย่างไร','เข้าใจว่า AI ช่วยเขียนโค้ด ออกแบบ วิเคราะห์ได้เร็วขึ้น สิ่งสำคัญคือความเข้าใจพื้นฐาน การตรวจสอบผล และเรียนรู้ตลอดชีวิต','hard',180),
('ประเทศไทยควรลงทุนด้านเทคโนโลยีหรือวิทยาศาสตร์เรื่องใดมากที่สุด เพราะอะไร','เลือก 1 เรื่องที่มีเหตุผลรองรับ เช่น พลังงานสะอาด EV เกษตรอัจฉริยะ เซมิคอนดักเตอร์ อธิบายผลต่อประเทศ','hard',180),
('เทคโนโลยีกับปัญหาสิ่งแวดล้อม/โลกร้อน คุณอยากใช้ความรู้ช่วยแก้อย่างไร','ยกตัวอย่างเป็นรูปธรรม เช่น พลังงานหมุนเวียน วัสดุยั่งยืน การจัดการขยะ แสดงความตั้งใจใช้วิศวกรรมเพื่อสังคม','medium',150),
('ความเป็นส่วนตัวของข้อมูล (เช่น PDPA) สำคัญกับงานเทคโนโลยีอย่างไร','แสดงความเข้าใจว่านักพัฒนาต้องออกแบบโดยคำนึงถึงความปลอดภัยและความยินยอมของผู้ใช้ ไม่ใช่แค่ทำให้ระบบทำงานได้','hard',150),
('ถ้าโค้ดหรือระบบที่คุณสร้างมี bug ที่กระทบผู้ใช้จำนวนมาก จะรับผิดชอบอย่างไร','แสดงจริยธรรมวิศวกร: แจ้งตามจริง แก้ไขเร่งด่วน หาสาเหตุเชิงระบบเพื่อป้องกันซ้ำ ไม่ปกปิด','medium',150)
) as t(q,g,d,s);

-- ── ครุศาสตร์ ──
with c as (select id from iv_categories where name='ครุศาสตร์ · ศึกษาศาสตร์')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('เมื่อนักเรียนใช้ AI ทำการบ้าน ครูควรวางตัวและออกแบบการเรียนอย่างไร','แสดงมุมมองสร้างสรรค์: สอนให้ใช้อย่างมีวิจารณญาณ ออกแบบงานที่วัดกระบวนการคิด ไม่ใช่แค่ผลลัพธ์ ปรับตัวแทนการห้าม','hard',180),
('ปัญหาสุขภาพจิตของนักเรียนที่เพิ่มขึ้น ครูมีบทบาทช่วยอย่างไร','เน้นการสังเกต รับฟังโดยไม่ตัดสิน สร้างห้องเรียนปลอดภัย และส่งต่อผู้เชี่ยวชาญเมื่อจำเป็น','hard',180),
('ความเหลื่อมล้ำทางการศึกษา (เด็กเมือง-ชนบท, ออนไลน์) คุณอยากช่วยลดอย่างไร','ยกแนวทางที่ทำได้จริงในฐานะครู เช่น สื่อที่เข้าถึงง่าย ใส่ใจเด็กที่ตามไม่ทัน แสดงจิตวิญญาณความเป็นครู','hard',180),
('คิดอย่างไรกับการเรียนรู้เชิงรุก (Active Learning) แทนการท่องจำ','แสดงความเข้าใจว่าผู้เรียนควรได้คิด ลงมือ และเชื่อมโยงกับชีวิตจริง ยกตัวอย่างกิจกรรมที่จะใช้','medium',150),
('ถ้าต้องสอนนักเรียนที่มีความหลากหลาย (ความสามารถ/พื้นฐานต่างกัน) ในห้องเดียว จะทำอย่างไร','แสดงแนวคิดการสอนที่ยืดหยุ่น แบ่งกลุ่ม มอบหมายงานตามระดับ และไม่ทิ้งใครไว้ข้างหลัง','hard',150)
) as t(q,g,d,s);

-- ── บริหาร บัญชี เศรษฐศาสตร์ ──
with c as (select id from iv_categories where name='บริหาร · บัญชี · เศรษฐศาสตร์')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('เศรษฐกิจไทยตอนนี้เผชิญความท้าทายเรื่องใดมากที่สุดในมุมมองของคุณ','เลือกประเด็นทันสมัยที่รู้จริง เช่น หนี้ครัวเรือน สังคมสูงวัย การแข่งขันกับต่างชาติ ท่องเที่ยว อธิบายเหตุผล','hard',180),
('AI และระบบอัตโนมัติจะเปลี่ยนงานด้านบัญชี/การเงินอย่างไร คุณจะเตรียมตัวอย่างไร','เข้าใจว่างานประจำ (บันทึกข้อมูล) จะถูกแทน แต่การวิเคราะห์ ให้คำปรึกษา และจริยธรรมยังต้องการคน เน้นพัฒนาทักษะขั้นสูง','hard',180),
('คิดอย่างไรกับกระแสความยั่งยืน (ESG) ที่ธุรกิจต้องใส่ใจสังคมและสิ่งแวดล้อม','แสดงความเข้าใจว่าธุรกิจยุคใหม่ต้องดูกำไรควบคู่ความรับผิดชอบ ยกตัวอย่างและมองว่าเป็นโอกาสไม่ใช่ภาระ','hard',180),
('การตลาดผ่าน influencer และโซเชียลเปลี่ยนพฤติกรรมผู้บริโภคอย่างไร','วิเคราะห์ทั้งพลัง (เข้าถึงตรงกลุ่ม สร้างความเชื่อ) และความเสี่ยง (โฆษณาเกินจริง การรีวิวหลอก) อย่างสมดุล','medium',150),
('ถ้าธุรกิจที่คุณดูแลกำลังขาดทุน คุณจะวิเคราะห์และตัดสินใจอย่างไร','แสดงกระบวนการคิด: หาสาเหตุจากข้อมูล (ต้นทุน รายได้ ตลาด) พิจารณาทางเลือก ตัดสินใจบนเหตุผลไม่ใช่อารมณ์','hard',180)
) as t(q,g,d,s);

-- ── มนุษยศาสตร์ สังคม นิติ รัฐศาสตร์ ──
with c as (select id from iv_categories where name='มนุษยศาสตร์ · สังคม · นิติ · รัฐศาสตร์')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('ข่าวปลอม (Fake News) และ AI ที่สร้างเนื้อหาปลอมได้ ส่งผลต่อสังคมและประชาธิปไตยอย่างไร','วิเคราะห์ผลกระทบต่อความเชื่อใจ การเลือกตั้ง และเสนอแนวทาง เช่น การรู้เท่าทันสื่อ กฎหมาย ความรับผิดชอบของแพลตฟอร์ม','hard',180),
('กฎหมายควรปรับตัวอย่างไรกับเทคโนโลยีใหม่ เช่น AI, คริปโต, ข้อมูลส่วนบุคคล','แสดงความเข้าใจว่ากฎหมายมักตามเทคโนโลยีไม่ทัน ต้องสมดุลระหว่างการคุ้มครองประชาชนกับการไม่ปิดกั้นนวัตกรรม','hard',180),
('ประเด็นสิทธิมนุษยชนหรือความเท่าเทียมเรื่องใดที่คุณให้ความสำคัญ เพราะอะไร','เลือกเรื่องที่รู้จริงและอธิบายได้ แสดงความเข้าใจเชิงหลักการและเปิดรับความเห็นต่าง ไม่ใช้อารมณ์','hard',180),
('คนรุ่นใหม่มีส่วนร่วมทางการเมืองผ่านโซเชียลมากขึ้น คุณมองปรากฏการณ์นี้อย่างไร','วิเคราะห์สองด้าน: การมีส่วนร่วมและตื่นตัวเป็นเรื่องดี แต่ต้องระวังข้อมูลผิดและการแบ่งขั้ว แสดงวุฒิภาวะ','medium',180),
('ถ้าต้องไกล่เกลี่ยความขัดแย้งระหว่างสองฝ่ายที่เห็นต่างกันสุดขั้ว จะเริ่มอย่างไร','แสดงทักษะการรับฟังทุกฝ่าย หาจุดร่วม ใช้ข้อเท็จจริงและหลักการ มุ่งทางออกที่ทุกฝ่ายยอมรับได้','hard',180)
) as t(q,g,d,s);

-- ── ศิลปกรรม สถาปัตย์ นิเทศ ──
with c as (select id from iv_categories where name='ศิลปกรรม · สถาปัตย์ · นิเทศศาสตร์')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('AI สร้างภาพ/งานออกแบบได้แล้ว คุณคิดว่าคุณค่าของนักออกแบบมนุษย์อยู่ตรงไหน','เน้นว่า AI เป็นเครื่องมือ แต่แนวคิด การเล่าเรื่อง รสนิยม บริบททางวัฒนธรรม และความหมายยังต้องการมนุษย์ พร้อมประเด็นจริยธรรม/ลิขสิทธิ์','hard',180),
('งานออกแบบที่คำนึงถึงความยั่งยืนและสิ่งแวดล้อม สำคัญอย่างไรในยุคนี้','แสดงความเข้าใจว่าการเลือกวัสดุ กระบวนการ และอายุการใช้งานมีผลต่อโลก นักออกแบบมีความรับผิดชอบ ยกตัวอย่างได้','medium',150),
('คอนเทนต์สั้น (TikTok/Reels) เปลี่ยนวงการสื่อสารและความสนใจของคนอย่างไร','วิเคราะห์ทั้งโอกาส (เข้าถึงเร็ว สร้างสรรค์) และความท้าทาย (สมาธิสั้น เนื้อหาฉาบฉวย) แสดงมุมมองนักสื่อสารมืออาชีพ','medium',150),
('การออกแบบเพื่อทุกคน (Universal/Inclusive Design) มีความหมายกับคุณอย่างไร','แสดงความเข้าใจว่างานที่ดีต้องเข้าถึงได้สำหรับคนหลากหลาย รวมถึงผู้พิการ ผู้สูงอายุ ยกตัวอย่างประกอบ','medium',150),
('ถ้าลูกค้าขอให้ทำงานที่ขัดกับหลักการหรือรสนิยมของคุณ จะจัดการอย่างไร','แสดงความเป็นมืออาชีพ: รับฟังความต้องการ อธิบายเหตุผลเชิงออกแบบ หาจุดสมดุล และรักษามาตรฐานงาน','hard',150)
) as t(q,g,d,s);

-- ── English ──
with c as (select id from iv_categories where name='ภาษาอังกฤษ (English Interview)')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds, lang)
select c.id, q, g, d, s, 'en' from c, (values
('How do you use AI tools like ChatGPT in your studies, and where do you draw the line?','Show you use it as a thinking aid, not for cheating. Explain academic honesty and give a real example of appropriate use.','hard',150),
('What social or global issue do you care about the most, and why?','Pick a current, real issue you understand. State facts first, then a reasoned opinion. Show maturity and openness.','hard',150),
('How do you deal with stress and take care of your mental health?','Answer honestly with methods that work for you. Show you know when to seek support instead of coping alone.','medium',120),
('Do you think studying abroad or in an international program is worth it? Why?','Give a balanced view: exposure, language, networks vs cost and adjustment. Connect to your own goals.','medium',150),
('What is one skill you want to develop in the next few years, and how?','Choose a concrete skill, explain why it matters for your field, and give a realistic plan to build it.','medium',120)
) as t(q,g,d,s);

-- ── MMI ──
with c as (select id from iv_categories where name='MMI · จริยธรรมทางการแพทย์ (กสพท)')
insert into iv_questions (category_id, question_text, guide_answer, difficulty, suggested_seconds)
select c.id, q, g, d, s from c, (values
('ถ้าโรงพยาบาลนำ AI มาช่วยตัดสินใจรักษา แล้ว AI แนะนำต่างจากความเห็นของคุณ จะทำอย่างไร','แสดงหลักคิด: AI เป็นข้อมูลประกอบ แพทย์ยังต้องใช้วิจารณญาณและรับผิดชอบ ตรวจสอบเหตุผลทั้งสองทาง คำนึงถึงผู้ป่วยเป็นหลัก','hard',180),
('ผู้ป่วยค้นข้อมูลจากอินเทอร์เน็ต/โซเชียลมาเถียงการวินิจฉัยของคุณ จะรับมืออย่างไร','รับฟังด้วยความเคารพ ไม่ดูถูก อธิบายด้วยหลักฐานอย่างเข้าใจง่าย สร้างความไว้วางใจร่วมกันในการตัดสินใจ','hard',180),
('มีวัคซีน/ยาจำกัดในภาวะวิกฤต ต้องจัดสรรอย่างไรให้เป็นธรรม','แสดงหลักจริยธรรม: ใช้เกณฑ์ทางการแพทย์และความเป็นธรรม โปร่งใส ไม่เลือกปฏิบัติด้วยฐานะหรืออคติ ยอมรับความยากของการตัดสินใจ','hard',180),
('เพื่อนร่วมงานโพสต์ข้อมูลผู้ป่วยลงโซเชียลโดยไม่ปิดบังตัวตน คุณจะทำอย่างไร','ยึดหลักความลับผู้ป่วย: เตือนเพื่อนโดยตรงให้ลบ อธิบายผลกระทบ หากไม่แก้ไขต้องรายงานตามระบบ ไม่เพิกเฉย','hard',180),
('ถ้าคุณทำงานหนักจนเหนื่อยล้า (burnout) และกลัวว่าจะกระทบผู้ป่วย จะจัดการอย่างไร','แสดงว่ารู้จักดูแลตัวเองและความปลอดภัยผู้ป่วยมาก่อน กล้าขอความช่วยเหลือ พักเมื่อจำเป็น ไม่ฝืนจนเสี่ยงผิดพลาด','hard',180)
) as t(q,g,d,s);
